<?php// checkout.phpsession_start();// In het script doen we het ook maar even stap voor stap.///   Naar database wegschrijven		//@@@@		include '../assets/dbconnect.php';	// Stap 1, zet de order in de order tabel$sql = "INSERT INTO alc_bestelling			 (klantnummer, besteldatum)			 VALUES			 (".$_SESSION['klantnr'].",".date().")";	// Verzin iets moois voor de date() functie$query = mysql_query($sql) or die (mysql_error()."<br>in file ".__FILE__." on line ".__LINE__);$ordernr = mysql_insert_id(); // Die hebben we later nodig, is dus ordernr (bestelnr)// Stap 2, winkelwagen splitten en in de database zetten$cart = explode("|",$_SESSION['cart']);foreach($cart as $products) {	// Split	/*		$product[x] -->			 x == 0 -> product id			 x == 1 -> hoeveelheid	*/	$product = explode(",",$products);		$iSql = "INSERT INTO alc_bestelregel					(bestelnummer, productnummer, aantal_besteld)					VALUES					(".$ordernr.", ".$product[0].", ".$product[1].")";	$iQuery = mysql_query($iSql) or die (mysql_error()."<br>in file ".__FILE__." on line ".__LINE__);}echo "<p>De bestelling is toegevoegd!</p>";?>